impl ToolHandler {
    pub fn new(auto_approve: bool, security_profile: String, approval_mode: String) -> Self {
        Self { auto_approve, security_profile, approval_mode, proot: None, plugins: None, cache: ToolResultCache::new(60), mcp_manager: None }
    }

    /// Set cache TTL in seconds.
    pub fn set_cache_ttl(&mut self, ttl_secs: u64) {
        self.cache = ToolResultCache::new(ttl_secs);
    }

    /// Configure MCP servers from config.
    pub fn set_mcp_servers(&mut self, configs: &[crate::mcp_client::McpServerConfig]) {
        if !configs.is_empty() {
            self.mcp_manager = Some(crate::mcp_client::McpManager::from_configs(configs));
        }
    }

    /// Enable proot sandbox with the given allowed dirs.
    pub fn enable_proot(&mut self, working_dir: &str, allowed_dirs: Vec<String>) {
        let config = ProotConfig {
            allowed_dirs,
            ..ProotConfig::default()
        };
        let mut sandbox = ProotSandbox::new(working_dir, config);
        if sandbox.is_available() {
            self.proot = Some(sandbox);
        } else {
            eprintln!("[Warning] proot sandbox requested but proot not found. Install with: pkg install proot");
        }
    }

    /// Load plugins from a directory. Returns number of plugins loaded.
    pub fn load_plugins(&mut self, dir: &str) -> usize {
        let mut pm = PluginManager::new();
        let count = pm.load_dir(dir);
        if count > 0 {
            self.plugins = Some(pm);
        }
        count
    }

    /// Load plugins from the default directory (~/.agent-loop/plugins/).
    pub fn load_default_plugins(&mut self) -> usize {
        let dir = PluginManager::default_dir();
        if dir.exists() {
            self.load_plugins(dir.to_str().unwrap_or(""))
        } else {
            0
        }
    }

    /// Get all tool schemas (built-in + plugins) for API tool_use format.
    pub fn get_all_tool_schemas(&self) -> Vec<serde_json::Value> {
        let mut schemas = crate::tools::tool_schemas_json().clone();
        if let Some(ref pm) = self.plugins {
            schemas.extend(pm.get_tool_schemas());
        }
        schemas
    }

    /// Look up the SecurityProfileSpec for the current profile.
    fn get_profile_spec(&self) -> Option<&'static SecurityProfileSpec> {
        use crate::security::SECURITY_PROFILES;
        SECURITY_PROFILES.iter()
            .find(|(name, _)| *name == self.security_profile)
            .map(|(_, spec)| spec)
    }
}


impl ToolHandler {
    /// Check if a path is allowed by security rules.
    /// Respects security_profile: "open" skips all checks.
    pub fn check_path_allowed(&self, path: &str) -> bool {
        use crate::security::*;

        // Open profile skips all path checks
        if let Some(spec) = self.get_profile_spec() {
            if !spec.path_validation {
                return true;
            }
        }

        // Check exact blocked paths
        for blocked in BLOCKED_PATHS.iter() {
            if path == *blocked {
                return false;
            }
        }

        // Check blocked prefixes
        for prefix in BLOCKED_PATH_PREFIXES.iter() {
            if path.starts_with(prefix) {
                return false;
            }
        }

        // Check home directory patterns
        if let Some(home) = std::env::var_os("HOME") {
            let home = home.to_string_lossy();
            for pattern in BLOCKED_HOME_PATTERNS.iter() {
                let blocked_path = format!("{}/{}", home, pattern);
                if path.starts_with(&blocked_path) {
                    return false;
                }
            }
        }

        true
    }

    /// Check if a command matches any blocked patterns.
    /// Respects security_profile: "open" skips checks, "guarded" adds extra blocks,
    /// "paranoid" uses allowlist-only mode.
    pub fn is_command_blocked(&self, command: &str) -> Option<String> {
        use crate::security::*;

        // Open profile skips all command checks
        if let Some(spec) = self.get_profile_spec() {
            if !spec.command_validation {
                return None;
            }
        }

        // Paranoid mode: allowlist-only (safe + confirm patterns)
        if self.security_profile == "paranoid" {
            let is_safe = PARANOID_SAFE.iter().any(|pat| {
                regex::Regex::new(pat).map(|re| re.is_match(command)).unwrap_or(false)
            });
            let is_confirm = PARANOID_CONFIRM.iter().any(|pat| {
                regex::Regex::new(pat).map(|re| re.is_match(command)).unwrap_or(false)
            });
            if !is_safe && !is_confirm {
                return Some("Command not in paranoid allowlist".to_string());
            }
            return None;
        }

        // Standard blocked command patterns (cautious + guarded)
        for (pattern, description) in BLOCKED_COMMAND_PATTERNS.iter() {
            if let Ok(re) = regex::Regex::new(pattern) {
                if re.is_match(command) {
                    return Some(description.to_string());
                }
            }
        }

        // Guarded mode: additional blocked patterns
        if self.security_profile == "guarded" {
            for pattern in GUARDED_EXTRA_BLOCKS.iter() {
                if let Ok(re) = regex::Regex::new(pattern) {
                    if re.is_match(command) {
                        return Some(format!("Blocked by guarded profile: {}", pattern));
                    }
                }
            }
        }

        None
    }

    /// Check if a tool requires approval based on approval_mode.
    /// Returns true if the tool is approved to execute, false if blocked.
    pub fn check_approval(&self, tool_name: &str) -> bool {
        match self.approval_mode.as_str() {
            "yolo" => true,
            "plan" => {
                // Plan mode: only read is allowed
                matches!(tool_name, "read")
            }
            "auto_edit" => {
                // Auto-approve read and edit, block bash and write
                matches!(tool_name, "read" | "edit" | "write")
            }
            "default" => {
                if self.auto_approve {
                    return true;
                }
                // Read is always auto-approved
                if tool_name == "read" {
                    return true;
                }
                // For other tools, prompt user
                true // Return true, actual prompt happens in confirm_tool_execution
            }
            _ => true,
        }
    }

    /// Interactive confirmation for tool execution with argument preview.
    /// Returns true if the user approves, false to skip.
    pub fn confirm_tool_execution(&self, tool_call: &ToolCall) -> bool {
        // Auto-approve in yolo mode or if auto_approve is set
        if self.approval_mode == "yolo" || self.auto_approve {
            return true;
        }
        // Read is always safe
        if tool_call.name == "read" {
            return true;
        }
        // Plan mode blocks all non-read tools
        if self.approval_mode == "plan" {
            eprintln!("  [plan mode] Blocked: {}", tool_call.name);
            return false;
        }
        // auto_edit mode: allow read/edit/write without prompt
        if self.approval_mode == "auto_edit" && matches!(tool_call.name.as_str(), "edit" | "write") {
            return true;
        }

        // Show tool details for confirmation
        let is_destructive = matches!(tool_call.name.as_str(), "bash" | "write" | "edit");
        let label = if is_destructive { "DESTRUCTIVE" } else { "Tool" };
        eprintln!("  [{}] {} tool:", label, tool_call.name);

        // Show relevant arguments preview
        match tool_call.name.as_str() {
            "bash" => {
                if let Some(cmd) = tool_call.arguments.get("command").and_then(|v| v.as_str()) {
                    let preview = if cmd.len() > 120 { &cmd[..120] } else { cmd };
                    eprintln!("    command: {}", preview);
                }
            }
            "write" | "edit" => {
                if let Some(path) = tool_call.arguments.get("file_path").and_then(|v| v.as_str()) {
                    eprintln!("    file: {}", path);
                }
            }
            _ => {
                // Show first argument key for plugin tools
                if let Some((key, val)) = tool_call.arguments.iter().next() {
                    let preview = val.to_string();
                    let preview = if preview.len() > 80 { &preview[..80] } else { &preview };
                    eprintln!("    {}: {}", key, preview);
                }
            }
        }

        eprint!("  Execute? [y/N] ");
        use std::io::Write;
        std::io::stderr().flush().ok();
        let mut input = String::new();
        if std::io::stdin().read_line(&mut input).is_ok() {
            input.trim().eq_ignore_ascii_case("y")
        } else {
            false
        }
    }

    /// Validate tool call arguments against known schemas.
    /// Returns Some(error_message) if validation fails, None if ok.
    pub fn validate_tool_args(&self, tool_call: &ToolCall) -> Option<String> {
        let required: &[&str] = match tool_call.name.as_str() {
            "bash" => &["command"],
            "read" => &["path"],
            "write" => &["path", "content"],
            "edit" => &["path", "old_string", "new_string"],
            _ => return None, // No schema for plugin/MCP tools
        };
        let missing: Vec<&str> = required.iter()
            .filter(|&&p| !tool_call.arguments.contains_key(p))
            .copied()
            .collect();
        if missing.is_empty() {
            None
        } else {
            Some(format!("Missing required parameter(s): {}", missing.join(", ")))
        }
    }
}


impl ToolHandler {
    /// Execute a tool call and return the result.
    pub fn execute(&mut self, tool_call: &ToolCall) -> ToolResult {
        // Check approval mode before executing
        if !self.check_approval(&tool_call.name) {
            return ToolResult {
                success: false,
                output: format!("Tool '{}' blocked by approval mode '{}'", tool_call.name, self.approval_mode),
                tool_name: tool_call.name.clone(),
            };
        }

        // Validate required parameters
        if let Some(err) = self.validate_tool_args(tool_call) {
            return ToolResult {
                success: false,
                output: format!("[Validation] {}", err),
                tool_name: tool_call.name.clone(),
            };
        }

        // Check cache for non-destructive tools
        if let Some(cached) = self.cache.get(&tool_call.name, &tool_call.arguments) {
            return cached.clone();
        }

        // MCP tool dispatch (tool names starting with "mcp:")
        if tool_call.name.starts_with("mcp:") {
            let result = if let Some(ref mut mgr) = self.mcp_manager {
                match mgr.dispatch(&tool_call.name, serde_json::json!(tool_call.arguments)) {
                    Some(val) => ToolResult {
                        success: true,
                        output: serde_json::to_string_pretty(&val).unwrap_or_default(),
                        tool_name: tool_call.name.clone(),
                    },
                    None => ToolResult {
                        success: false,
                        output: format!("MCP tool not found: {}", tool_call.name),
                        tool_name: tool_call.name.clone(),
                    },
                }
            } else {
                ToolResult {
                    success: false,
                    output: "No MCP servers configured".to_string(),
                    tool_name: tool_call.name.clone(),
                }
            };
            self.cache.put(&tool_call.name, &tool_call.arguments, result.clone());
            return result;
        }

        let result = match tool_call.name.as_str() {
            "bash" => self.handle_bash(&tool_call.arguments),
            "read" => self.handle_read(&tool_call.arguments),
            "write" => self.handle_write(&tool_call.arguments),
            "edit" => self.handle_edit(&tool_call.arguments),
            _ => {
                // Check plugin tools
                if let Some(ref pm) = self.plugins {
                    if let Some(cmd) = pm.execute(&tool_call.name, &tool_call.arguments) {
                        // Execute plugin command via bash
                        let mut plugin_args = std::collections::HashMap::new();
                        plugin_args.insert("command".to_string(), serde_json::json!(cmd));
                        let mut r = self.handle_bash(&plugin_args);
                        r.tool_name = tool_call.name.clone();
                        return r;
                    }
                }
                ToolResult {
                    success: false,
                    output: format!("Unknown tool: {}", tool_call.name),
                    tool_name: tool_call.name.clone(),
                }
            },
        };

        // Store in cache
        self.cache.put(&tool_call.name, &tool_call.arguments, result.clone());
        result
    }

    /// Async tool execution — uses tokio::process::Command for plugin tools.
    /// Falls back to sync execute() for built-in tools.
    pub async fn execute_async(&mut self, tool_call: &ToolCall) -> ToolResult {
        // Check if this is a plugin tool with async support
        if let Some(ref pm) = self.plugins {
            if pm.has_tool(&tool_call.name) {
                if let Some((success, output)) = pm.execute_async(&tool_call.name, &tool_call.arguments).await {
                    return ToolResult {
                        success,
                        output,
                        tool_name: tool_call.name.clone(),
                    };
                }
            }
        }
        // Fall back to sync execution for built-in tools
        self.execute(tool_call)
    }

    fn handle_bash(&mut self, args: &std::collections::HashMap<String, serde_json::Value>) -> ToolResult {
        let command = args.get("command")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if let Some(reason) = self.is_command_blocked(command) {
            return ToolResult {
                success: false,
                output: format!("Command blocked: {}", reason),
                tool_name: "bash".to_string(),
            };
        }

        // If proot is enabled, wrap the command in proot
        let (exec_cmd, exec_env) = if let Some(ref mut proot) = self.proot {
            match proot.wrap_command(command) {
                Ok(wrapped) => {
                    let env_overrides = proot.build_env_overrides();
                    (wrapped, Some(env_overrides))
                }
                Err(e) => {
                    return ToolResult {
                        success: false,
                        output: format!("Proot error: {}", e),
                        tool_name: "bash".to_string(),
                    };
                }
            }
        } else {
            (command.to_string(), None)
        };

        let mut cmd = Command::new("bash");
        cmd.arg("-c").arg(&exec_cmd)
           .stdout(Stdio::piped()).stderr(Stdio::piped());

        // Apply proot env overrides
        if let Some(env_overrides) = exec_env {
            for (key, val) in env_overrides {
                cmd.env(key, val);
            }
        }

        match cmd.output() {
            Ok(output) => {
                let stdout = String::from_utf8_lossy(&output.stdout);
                let stderr = String::from_utf8_lossy(&output.stderr);
                let combined = if stderr.is_empty() {
                    stdout.to_string()
                } else {
                    format!("{}
{}", stdout, stderr)
                };
                ToolResult {
                    success: output.status.success(),
                    output: combined,
                    tool_name: "bash".to_string(),
                }
            }
            Err(e) => ToolResult {
                success: false,
                output: format!("Error: {}", e),
                tool_name: "bash".to_string(),
            },
        }
    }

    fn handle_read(&self, args: &std::collections::HashMap<String, serde_json::Value>) -> ToolResult {
        let path = args.get("file_path")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if !self.check_path_allowed(path) {
            return ToolResult {
                success: false,
                output: format!("Path blocked: {}", path),
                tool_name: "read".to_string(),
            };
        }

        match std::fs::read_to_string(path) {
            Ok(content) => ToolResult {
                success: true,
                output: content,
                tool_name: "read".to_string(),
            },
            Err(e) => ToolResult {
                success: false,
                output: format!("Error reading {}: {}", path, e),
                tool_name: "read".to_string(),
            },
        }
    }

    fn handle_write(&self, args: &std::collections::HashMap<String, serde_json::Value>) -> ToolResult {
        let path = args.get("file_path")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let content = args.get("content")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if !self.check_path_allowed(path) {
            return ToolResult {
                success: false,
                output: format!("Path blocked: {}", path),
                tool_name: "write".to_string(),
            };
        }

        match std::fs::write(path, content) {
            Ok(()) => ToolResult {
                success: true,
                output: format!("Wrote {} bytes to {}", content.len(), path),
                tool_name: "write".to_string(),
            },
            Err(e) => ToolResult {
                success: false,
                output: format!("Error writing {}: {}", path, e),
                tool_name: "write".to_string(),
            },
        }
    }

    fn handle_edit(&self, args: &std::collections::HashMap<String, serde_json::Value>) -> ToolResult {
        let path = args.get("file_path")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let old_string = args.get("old_string")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let new_string = args.get("new_string")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if !self.check_path_allowed(path) {
            return ToolResult {
                success: false,
                output: format!("Path blocked: {}", path),
                tool_name: "edit".to_string(),
            };
        }

        match std::fs::read_to_string(path) {
            Ok(content) => {
                if !content.contains(old_string) {
                    return ToolResult {
                        success: false,
                        output: "old_string not found in file".to_string(),
                        tool_name: "edit".to_string(),
                    };
                }
                let new_content = content.replacen(old_string, new_string, 1);
                match std::fs::write(path, &new_content) {
                    Ok(()) => ToolResult {
                        success: true,
                        output: format!("Edited {}", path),
                        tool_name: "edit".to_string(),
                    },
                    Err(e) => ToolResult {
                        success: false,
                        output: format!("Error writing {}: {}", path, e),
                        tool_name: "edit".to_string(),
                    },
                }
            }
            Err(e) => ToolResult {
                success: false,
                output: format!("Error reading {}: {}", path, e),
                tool_name: "edit".to_string(),
            },
        }
    }
}


use std::time::Instant;

/// Cache for tool execution results, keyed by (tool_name, canonical_args).
pub struct ToolResultCache {
    cache: std::collections::HashMap<String, (Instant, ToolResult)>,
    ttl: std::time::Duration,
    skip_tools: std::collections::HashSet<String>,
}

impl ToolResultCache {
    pub fn new(ttl_secs: u64) -> Self {
        let mut skip = std::collections::HashSet::new();
        skip.insert("bash".to_string());
        skip.insert("write".to_string());
        skip.insert("edit".to_string());
        Self { cache: std::collections::HashMap::new(), ttl: std::time::Duration::from_secs(ttl_secs), skip_tools: skip }
    }

    fn make_key(tool_name: &str, args: &std::collections::HashMap<String, serde_json::Value>) -> String {
        let canonical = serde_json::to_string(args).unwrap_or_default();
        format!("{}:{}", tool_name, canonical)
    }

    pub fn get(&self, tool_name: &str, args: &std::collections::HashMap<String, serde_json::Value>) -> Option<&ToolResult> {
        if self.skip_tools.contains(tool_name) { return None; }
        let key = Self::make_key(tool_name, args);
        if let Some((ts, result)) = self.cache.get(&key) {
            if ts.elapsed() < self.ttl {
                return Some(result);
            }
        }
        None
    }

    pub fn put(&mut self, tool_name: &str, args: &std::collections::HashMap<String, serde_json::Value>, result: ToolResult) {
        if self.skip_tools.contains(tool_name) { return; }
        let key = Self::make_key(tool_name, args);
        self.cache.insert(key, (Instant::now(), result));
    }

    pub fn clear(&mut self) { self.cache.clear(); }
    pub fn len(&self) -> usize { self.cache.len() }
}
